{"content": "     1|import { readFileSync, existsSync } from 'fs'
     2|import { join } from 'path'
     3|import { loadJSON } from './loader'
     4|
     5|const REPO = process.cwd()
     6|const LOCALES = ['es', 'en', 'nl', 'de']
     7|
     8|export function loadPageData(locale: string, slug: string) {
     9|  try {
    10|    const content = JSON.parse(readFileSync(join(REPO, 'content', `${locale}.json`), 'utf-8'))
    11|    let pageConfig: any = null
    12|    const pageId = slug === 'home' ? 'home' : slug
    13|    let pageConfigPath = slug
    14|    if (slug === 'home') pageConfigPath = 'home'
    15|    try { pageConfig = JSON.parse(readFileSync(join(REPO, 'nexa-pages', `${pageConfigPath}.json`), 'utf-8')) } catch {}
    16|    const images = JSON.parse(readFileSync(join(REPO, 'images.json'), 'utf-8'))
    17|    // Load testimonials data and inject into content
    18|    try {
    19|      const testimonials = JSON.parse(readFileSync(join(REPO, 'testimonials.json'), 'utf-8'))
    20|      content.testimonials = testimonials.testimonials
    21|    } catch {}
    22|    return { content, pageConfig, images, pageId, locale }
    23|  } catch { return null }
    24|}
    25|
    26|export function loadBlogPost(locale: string, slug: string) {
    27|  try {
    28|    const content = JSON.parse(readFileSync(join(REPO, 'content', `${locale}.json`), 'utf-8'))
    29|    const localePath = join(REPO, 'content', 'blog', `posts-${locale}.json`)
    30|    const fallbackPath = join(REPO, 'content', 'blog', 'posts.json')
    31|    const postsPath = existsSync(localePath) ? localePath : (existsSync(fallbackPath) ? fallbackPath : null)
    32|    if (!postsPath) return null
    33|    const posts = JSON.parse(readFileSync(postsPath, 'utf-8'))
    34|    const list = posts.posts || posts
    35|    const post = list.find((p: any) => p.slug === slug)
    36|    if (!post) {
    37|      try {
    38|        const mdx = readFileSync(join(REPO, 'content', 'blog', locale, `${slug}.mdx`), 'utf-8')
    39|        return { content, locale, post: { slug, body: mdx, title: slug.replace(/-/g,' '), excerpt: '' } }
    40|      } catch { return null }
    41|    }
    42|    return { content, locale, post }
    43|  } catch { return null }
